gen-control.c:script:
const valueProp = dispMeta?.id || 'docStatus';
const labelProp = propMeta?.['graphql:labelProp'] || (valueProp + '_label');
return {
    type: "tpl",
    tpl: '<span class="label label-${' + valueProp
        + " == 'ACTIVE' ? 'primary' : 'default'}\" "
        + "${" + valueProp
        + " == 'CANCELLED' ? \"style='text-decoration:line-through'\" : ''}>"
        + "${" + labelProp + "}</span>"
};

const valueProp = dispMeta?.id || 'approveStatus';
const labelProp = propMeta?.['graphql:labelProp'] || (valueProp + '_label');
return {
    type: "tpl",
    tpl: '<span class="label label-${' + valueProp
        + " == 'APPROVED' ? 'success' : "
        + valueProp + " == 'REJECTED' ? 'danger' : "
        + valueProp + " == 'SUBMITTED' ? 'info' : 'default'}\">"
        + "${" + labelProp + "}</span>"
};

return {
    type: 'button',
    label: '从订单导入行',
    level: 'primary',
    icon: 'fa fa-download',
    tooltip: '打开销售订单行选择器，挑选订单行后自动映射填入子表',
    actionType: 'dialog',
    dialog: {
        title: '从销售订单导入行',
        size: 'lg',
        actions: [
            {
                type: 'button',
                label: '确认导入到子表',
                level: 'primary',
                onEvent: {
                    click: {
                        actions: [
                            {
                                actionType: 'setValue',
                                componentName: 'form',
                                args: {
                                    value: {
                                        lines: '${selectedOrderLines | map: {lineNo: __index + 1, materialId: materialId, uoMId: uoMId, quantity: quantity, unitPrice: unitPrice, taxRate: taxRate | default:0, amount: amount | default:0, taxAmount: taxAmount | default:0, orderLineId: id}}'
                                    }
                                }
                            },
                            { actionType: 'closeDialog' }
                        ]
                    }
                }
            }
        ],
        body: [
            {
                type: 'picker',
                name: 'selectedOrderLines',
                label: '选择销售订单行',
                source: '/erp/sal/pages/ErpSalOrderLine/picker.page.yaml',
                multiple: true,
                valueField: 'id',
                labelField: 'lineNo',
                joinValues: false,
                extractValue: false,
                required: true
            }
        ]
    }
};
